import{_ as t,o as i,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"6. Certificate Of Service","description":"","frontmatter":{"title":"6. Certificate Of Service","eba":"Allied Health Professionals 2021-2026","topics":["appendices","employment","forms"]},"headers":[],"relativePath":"ebas/allied-health/appendices/6-certificate-of-service.md","filePath":"ebas/allied-health/appendices/6-certificate-of-service.md"}'),r={name:"ebas/allied-health/appendices/6-certificate-of-service.md"};function n(s,e,l,p,c,d){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_6-certificate-of-service" tabindex="-1">6. Certificate Of Service <a class="header-anchor" href="#_6-certificate-of-service" aria-label="Permalink to &quot;6. Certificate Of Service&quot;">​</a></h1><p>Formatting note</p><p>The appendix body below is rendered in a monospaced block to preserve the column layout of pay tables and forms. The block is excluded from the search index so search results stay short; find appendices by their title, number, topic or synonyms.</p><p>```text CERTIFICATE OF SERVICE [Name of Institution] [date] This is to certify that [Name of Employee] has been employed by this institution/society/board for a period of [years/months/etc.] from [date] to [date]. Specify hereunder full details of any additional service with a different Institution or Statutory Body that was recognised by [Name of employer]: ………………………………………………….. Specify hereunder full details of paid leave, unpaid leave or absences (including whether any such period constitutes Continuous Service), and periods represented by a payment made in lieu of leave or a transfer of leave upon termination of employment: ………………………………………………….. Specify hereunder full details of long service leave granted during service or on termination: ………………………………………………….. Signed ……………………………[Stamp of institution]</p><p>IN THE FAIR WORK COMMISSION</p><p>FWC Matter No.: AG2022/5276</p><p>Applicant:</p><p>Victorian Hospitals’ Industrial Association (VHIA)</p><pre><code>                 Undertaking – Section 190\n</code></pre><p>I, Stuart McCullough, Chief Executive Officer of VHIA (88 Maribyrnong Street, Footscray, Victoria) have the authority given to me by the Employers listed in Appendix A to give the following undertakings with respect to the Allied Health Professionals (Victorian Public Sector) (Single Interest Employers) Enterprise Agreement 2021-2026 (&quot;the Agreement&quot;):</p><ol><li><p>An Employee classified as a Medical Imaging Technologist (Radiographer), Nuclear Medicine Technologist or Radiation Therapy Technologist (Radiation Therapist) - 3 year degree will be paid the greater of the base rate of pay prescribed by the Agreement or the Health Professional Employee Level 1, Pay Point 2 (3 year degree entry) base rate of pay in the Health Professionals and Support Services Award 2020 (Award).</p></li><li><p>The relevant base rate of pay determined under paragraph 1 will be distributed to relevant Employers by the VHIA and a copy of the same information will be provided to the Health Services Union Victoria No. 3 Branch.</p></li><li><p>Where an Employee who is at least 18 years of age and is covered by the Agreement terminates the employment without giving the Notice of Termination required by clause 24.4 of the Agreement, then the Employer may deduct from wages due to the employee under the Agreement an amount that is no more than one week’s wages for the Employee.</p></li></ol><p>These undertakings are provided on the basis of issues raised by the Fair Work Commission in the application before the Fair Work Commission. Date: 15 December 2022 ```</p>',12)])])}const m=t(r,[["render",n]]);export{f as __pageData,m as default};
